fn main() {
    let s1 = String::from("hello"); // s1 是 "hello" 的所有者
    let s2 = s1;                      // 所有权转移到 s2，s1 失效
    // println!("{}", s1);            // 编译错误！s1 已被移动
    println!("{}", s2);               // OK，s2 是当前所有者
} // s2 离开作用域，"hello" 被自动释放

let x: i32 = 42;
let y = x;   // i32 实现了 Copy，x 仍然有效
println!("x={}, y={}", x, y); // OK

let v1 = vec![1, 2, 3];
let v2 = v1;  // Vec 没有 Copy，v1 被移动
// println!("{:?}", v1);  // 编译错误！

fn calculate_distance(a: &Vec2, b: &Vec2) -> f64 {
    // a 和 b 是不可变引用，可以同时存在
    let dx = (a.x - b.x) as f64;
    let dy = (a.y - b.y) as f64;
    (dx * dx + dy * dy).sqrt()
}

fn set_position(pos: &mut Vec2, x: i32, y: i32) {
    // pos 是可变引用，可以修改数据
    pos.x = x;
    pos.y = y;
}

/// 返回两个切片中较长的那个
fn longer<'a>(s1: &'a str, s2: &'a str) -> &'a str {
    if s1.len() > s2.len() { s1 } else { s2 }
}

// 使用示例
let result;
{
    let s2 = String::from("long string");
    let s1 = String::from("hi");
    result = longer(&s1, &s2);
} // s1, s2 离开作用域
