// 结构体持有引用时需要生命周期标注
struct TextRenderer<'a> {
    buffer: &'a mut [u8],  // 借用的缓冲区
    font: &'a Font,        // 借用的字体资源
}

// PathFinder 拥有自己的 Vec<u8>，不需要生命周期
struct PathFinder {
    obstacle_bitmap: Vec<u8>,      // 拥有所有权
    hard_obstacle_bitmap: Vec<u8>, // 拥有所有权
    dynamic_bitmap: Vec<u8>,       // 拥有所有权
}
